# -*- coding: utf-8 -*-
ROWS = [
(117,"单选","根据会计法律制度的规定，下列关于会计人员从事会计工作基本要求的表述中，不正确的是（）。",["A"],"会计从业资格证书已取消，从事会计工作不再要求取得该证书，A表述错误当选。会计人员应具备从事会计工作所需的专业能力、按规定参加继续教育、保守商业秘密，B、C、D正确。",[("A","从事会计工作必须取得会计从业资格证书"),("B","应当具备从事会计工作所需的专业能力"),("C","应当按照规定参加继续教育"),("D","应当保守商业秘密")]),
(117,"判断","担任单位会计机构负责人（会计主管人员）的，应当具备会计师以上专业技术职务资格或者从事会计工作三年以上经历。（）",["对"],"担任会计机构负责人（会计主管）应具备会计师以上专业技术职务资格，或从事会计工作三年以上经历。表述正确。"),
(119,"单选","下列会计法规制度中，层次最高的是（）。",["A"],"我国会计法规体系自上而下为：会计法（最高，全国人大常委会）、会计行政法规（国务院）、国家统一的会计制度（财政部部门规章）。会计法层次最高，选A。",[("A","《会计法》"),("B","《企业财务会计报告条例》"),("C","企业会计准则"),("D","《总会计师条例》")]),
(119,"判断","《企业财务会计报告条例》属于会计行政法规，由国务院制定。（）",["对"],"企业财务会计报告条例、总会计师条例属于会计行政法规，由国务院制定。表述正确。"),
(121,"单选","财务报告的目标之一是反映企业管理层（）的履行情况。",["A"],"财务报告两大目标：①提供与决策有用的信息；②反映企业管理层受托责任的履行情况。选A。",[("A","受托责任"),("B","纳税义务"),("C","社会责任"),("D","环保责任")]),
(121,"判断","向财务报告使用者提供与决策有用的信息，是财务报告目标之一。（）",["对"],"财务报告目标包括提供与决策有用的信息和反映管理层受托责任履行情况。表述正确。"),
(122,"多选","下列各项会计要素中，属于反映企业财务状况的有（）。",["A","B","C"],"六个会计要素中，资产、负债、所有者权益反映财务状况（资产=负债+所有者权益）；收入、费用、利润反映经营成果。选A、B、C。",[("A","资产"),("B","负债"),("C","所有者权益"),("D","收入")]),
(122,"判断","利润属于反映企业经营成果的会计要素。（）",["对"],"收入、费用、利润是反映经营成果的要素。表述正确。"),
(124,"单选","企业披露环境、社会和治理（ESG）等相关信息，属于（）。",["A"],"企业按要求披露环境、社会和治理（ESG）等相关信息，属于可持续信息披露，选A。",[("A","可持续信息披露"),("B","关联方披露"),("C","分部报告"),("D","或有事项披露")]),
(124,"判断","可持续信息披露涉及企业环境、社会和治理（ESG）等相关信息。（）",["对"],"可持续信息披露要求企业披露环境、社会和治理等可持续相关信息，提升信息透明度。表述正确。"),
(125,"多选","存货的确认应当同时满足的条件有（）。",["A","B"],"存货确认需同时满足：①与该存货有关的经济利益很可能流入企业；②成本能够可靠计量。已验收入库、已支付货款不是确认条件。选A、B。",[("A","与该存货有关的经济利益很可能流入企业"),("B","成本能够可靠计量"),("C","已经验收入库"),("D","已经支付货款")]),
(125,"判断","企业的周转材料属于存货。（）",["对"],"存货包括原材料、在产品、半成品、产成品、商品、周转材料等。表述正确。"),
(127,"单选","资产负债表日，存货应当按照（）计量。",["B"],"存货期末按成本与可变现净值孰低计量；成本高于可变现净值的，计提存货跌价准备。选B。",[("A","历史成本"),("B","成本与可变现净值孰低"),("C","公允价值"),("D","可变现净值")]),
(127,"判断","存货成本高于其可变现净值时，应计提存货跌价准备，差额计入资产减值损失。（）",["对"],"成本高于可变现净值时计提跌价准备，差额计入资产减值损失。表述正确。"),
(128,"单选","下列情形中，通常不表明存货的可变现净值低于成本的是（）。",["D"],"市价持续下跌且无回升希望、生产成本高于市价、产品更新换代滞销等表明可变现净值低于成本；市价短期小幅波动后回升不构成减值迹象，选D。",[("A","市价持续下跌且无回升希望"),("B","生产成本高于市价"),("C","产品更新换代导致滞销"),("D","市价短期内小幅波动后回升")]),
(128,"判断","存货因质量等原因发生毁损、陈旧，通常表明其可变现净值低于成本。（）",["对"],"因质量等导致毁损、陈旧属于存货减值迹象。表述正确。"),
(135,"多选","固定资产满足下列条件之一的，应予终止确认（）。",["A","B"],"固定资产满足之一终止确认：①处于处置状态；②预期通过使用或处置不能产生经济利益。提足折旧或使用满一定年限不是终止确认条件。选A、B。",[("A","该固定资产处于处置状态"),("B","预期通过使用或处置不能产生经济利益"),("C","已计提足额折旧"),("D","已使用满10年")]),
(135,"判断","固定资产已计提足额折旧但仍可继续使用的，应当终止确认。（）",["错"],"终止确认条件是处于处置状态或预期不能产生经济利益。提足折旧但仍在使用的不满足终止确认条件。表述错误。"),
(137,"单选","下列各项中，不属于无形资产的是（）。",["D"],"无形资产须可辨认；商誉不可辨认，不属于无形资产。专利权、商标权、土地使用权均属无形资产。选D。",[("A","专利权"),("B","商标权"),("C","土地使用权"),("D","商誉")]),
(137,"判断","无形资产是指企业拥有或者控制的没有实物形态的可辨认非货币性资产。（）",["对"],"无形资产的定义即没有实物形态的可辨认非货币性资产。表述正确。"),
(140,"单选","将研究成果或其他知识应用于某项计划或设计，以生产出新的产品，属于内部研究开发项目的（）。",["B"],"开发阶段是将研究成果应用于生产，针对性强、形成成果可能性较大；研究阶段为探索性、不确定性大。选B。",[("A","研究阶段"),("B","开发阶段"),("C","试运行阶段"),("D","准备阶段")]),
(140,"判断","内部研究开发项目研究阶段的支出，应于发生时计入当期损益。（）",["对"],"研究阶段支出全部费用化计入当期损益（管理费用）。表述正确。"),
(142,"单选","企业内部研究开发项目费用化的支出，期末应当转入（）。",["A"],"费用化支出先归集于研发支出——费用化支出，期末转入管理费用；资本化支出达到预定用途时转入无形资产。选A。",[("A","管理费用"),("B","无形资产"),("C","研发支出——资本化支出"),("D","销售费用")]),
(142,"判断","内部开发活动中符合资本化条件的支出，达到预定用途时应转入无形资产。（）",["对"],"资本化支出归集于研发支出——资本化支出，达到预定用途时转入无形资产。表述正确。"),
(146,"单选","企业出售无形资产，将取得价款扣除其账面价值及相关税费后的差额计入（）。",["C"],"出售无形资产的净损益计入资产处置损益。选C。",[("A","营业外收入"),("B","其他业务收入"),("C","资产处置损益"),("D","投资收益")]),
(146,"判断","企业出售无形资产形成的净损益，应当计入资产处置损益。（）",["对"],"出售无形资产的差额计入资产处置损益。表述正确。"),
(150,"单选","下列各项中，属于投资性房地产的是（）。",["A"],"投资性房地产是为赚取租金或资本增值而持有的房地产，如出租的办公楼。自用厂房、生产经营用土地使用权属固定资产/无形资产，作为存货的房地产属存货。选A。",[("A","出租的办公楼"),("B","自用的厂房"),("C","作为存货的房地产"),("D","生产经营用土地使用权")]),
(150,"判断","投资性房地产在同时满足经济利益很可能流入且成本能可靠计量时予以确认。（）",["对"],"投资性房地产确认需同时满足经济利益很可能流入和成本能可靠计量。表述正确。"),
(151,"单选","下列各项中，不应计入外购投资性房地产成本的是（）。",["D"],"投资性房地产按成本初始计量，包括购买价款、相关税费及可直接归属的支出；购入后发生的日常维修费计入当期损益，不计入成本。选D。",[("A","购买价款"),("B","相关税费"),("C","可直接归属于该资产的其他支出"),("D","购入后发生的日常维修费")]),
(151,"判断","投资性房地产应当按照成本进行初始计量。（）",["对"],"投资性房地产初始按成本计量。表述正确。"),
(153,"多选","对采用成本模式计量的投资性房地产，下列会计处理正确的有（）。",["A","B","C"],"成本模式下：建筑物计提折旧、土地使用权摊销、存在减值迹象时计提减值准备；减值准备一经计提以后期间不得转回。选A、B、C。",[("A","建筑物计提折旧"),("B","土地使用权进行摊销"),("C","存在减值迹象时计提减值准备"),("D","计提的减值准备以后期间可以转回")]),
(153,"判断","采用成本模式计量的投资性房地产计提的减值准备，以后会计期间不得转回。（）",["对"],"长期资产减值准备一经计提不得转回。表述正确。"),
(157,"单选","处置采用成本模式计量的投资性房地产，处置收入扣除账面价值和相关税费后的差额应计入（）。",["B"],"投资性房地产属于企业的日常经营活动，处置差额计入其他业务收入/其他业务成本。选B。",[("A","营业外收支"),("B","其他业务收入/其他业务成本"),("C","投资收益"),("D","资产处置损益")]),
(157,"判断","采用公允价值模式计量的投资性房地产处置时，应将原计入其他综合收益、累计公允价值变动等一并结转。（）",["对"],"公允价值模式下处置需结转累计公允价值变动等。表述正确。"),
(158,"多选","下列权益性投资中，属于长期股权投资核算范围的有（）。",["A","B","C"],"长期股权投资核算对子公司（控制）、合营企业（共同控制）、联营企业（重大影响）的投资；不具有控制、共同控制或重大影响的，作为金融资产核算。选A、B、C。",[("A","对子公司的投资"),("B","对合营企业的投资"),("C","对联营企业的投资"),("D","不具有重大影响的权益性投资")]),
(158,"判断","对被投资单位不具有控制、共同控制或重大影响的权益性投资，应作为金融资产核算。（）",["对"],"不构成控制、共同控制或重大影响的权益性投资属于金融资产，不属于长投。表述正确。"),
(160,"单选","对子公司的长期股权投资采用成本法核算，被投资单位宣告分派现金股利时，投资方应（）。",["A"],"成本法下，被投资单位宣告分派现金股利时确认为投资收益，不调整长期股权投资账面价值。选A。",[("A","确认为投资收益"),("B","增加长期股权投资账面价值"),("C","减少长期股权投资账面价值"),("D","计入其他综合收益")]),
(160,"判断","成本法下，被投资单位宣告分派现金股利，投资方不调整长期股权投资的账面价值。（）",["对"],"成本法下宣告现金股利确认投资收益，不调整长投账面价值。表述正确。"),
(162,"单选","投资方因增持股份对被投资单位由具有重大影响转为实施控制，其长期股权投资的后续计量应（）。",["B"],"重大影响（联营）采用权益法，控制（子公司）采用成本法；由重大影响转为控制，应由权益法转为成本法。选B。",[("A","由成本法转为权益法"),("B","由权益法转为成本法"),("C","由金融资产转为权益法"),("D","由权益法转为金融资产")]),
(162,"判断","因持股比例或影响程度变化，长期股权投资可在成本法、权益法及金融资产之间转换。（）",["对"],"影响程度变化时长投在成本法、权益法及金融资产间转换。表述正确。"),
(164,"单选","由两个或两个以上参与方共同控制的安排是（）。",["A"],"合营安排是由两个或以上参与方共同控制的安排，分为共同经营和合营企业。选A。",[("A","合营安排"),("B","联营安排"),("C","代理安排"),("D","委托安排")]),
(164,"判断","合营安排分为共同经营和合营企业两类。（）",["对"],"合营安排按参与方权利义务分为共同经营和合营企业。表述正确。"),
(165,"单选","关于共同经营中合营方的账务处理，下列说法正确的是（）。",["B"],"共同经营中合营方确认其单独所持及按份额享有或承担的资产、负债、收入、费用（而非按净额）。选B。",[("A","按享有的净资产份额确认"),("B","确认单独所持及按份额享有或承担的资产、负债、收入和费用"),("C","作为长期股权投资按权益法核算"),("D","不确认相关资产负债")]),
(165,"判断","共同经营中，合营方应确认其单独所持以及按份额享有或承担的资产、负债、收入和费用。（）",["对"],"共同经营合营方按份额确认资产负债收入费用，非按净额。表述正确。"),
(166,"判断","共同经营中不享有共同控制，但享有相关资产权利、承担相关负债义务的参与方，比照合营方进行会计处理。（）",["对"],"享有资产权利、承担负债义务的非共同控制参与方比照合营方处理。表述正确。"),
(166,"单选","共同经营中既不享有共同控制、也不享有相关资产权利的参与方，应按（）等规定处理。",["A"],"不享有共同控制且不享有相关资产权利的参与方，按金融资产等规定处理。选A。",[("A","金融资产"),("B","长期股权投资成本法"),("C","合并财务报表"),("D","权益法")]),
(167,"单选","资产减值是指资产的（）低于其账面价值。",["A"],"资产减值即资产可收回金额低于账面价值。选A。",[("A","可收回金额"),("B","公允价值"),("C","重置成本"),("D","账面余额")]),
(167,"多选","下列资产的减值，适用《企业会计准则第8号——资产减值》的有（）。",["A","B","C"],"该准则主要规范长期资产：固定资产、无形资产、商誉、长期股权投资、成本模式投资性房地产、资产组等；存货、金融资产、递延所得税资产适用各自准则。选A、B、C。",[("A","固定资产"),("B","无形资产"),("C","商誉"),("D","存货")]),
(170,"单选","确定资产的公允价值减去处置费用后的净额时，最优先采用的是（）。",["B"],"估计顺序：①公平交易中的销售协议价格；②活跃市场价格；③可获得的最佳信息估计。最优先为销售协议价格。选B。",[("A","活跃市场价格"),("B","公平交易中的销售协议价格"),("C","可获得的最佳信息估计"),("D","账面价值")]),
(170,"判断","确定资产公允价值减去处置费用后的净额，应优先采用公平交易中的销售协议价格。（）",["对"],"优先采用销售协议价格，其次活跃市场价格。表述正确。"),
(173,"单选","资产组是指企业可以认定的（）的最小资产组合。",["A"],"资产组是能够独立产生现金流入的最小资产组合。选A。",[("A","能够独立产生现金流入"),("B","能够独立计提折旧"),("C","能够独立核算"),("D","单独存放")]),
(173,"判断","难以对单项资产估计其可收回金额的，应当以该资产所属的资产组为基础进行减值测试。（）",["对"],"难以单独估计可收回金额时按所属资产组测试。表述正确。"),
(174,"单选","关于资产组账面价值的确定，下列说法正确的是（）。",["B"],"资产组账面价值应包括可直接归属以及可合理分摊的资产；可收回金额与账面价值的口径应一致。选B。",[("A","仅包括可直接归属的资产"),("B","应包括可直接归属及可合理分摊的资产"),("C","等于各单项资产账面价值之和减商誉"),("D","按可收回金额确定")]),
(174,"判断","确定资产组的账面价值与可收回金额时，二者的口径应当保持一致。（）",["对"],"账面价值与可收回金额口径一致。表述正确。"),
(175,"单选","包含商誉的资产组发生减值的，减值损失应当首先抵减（）。",["A"],"资产组减值损失先抵减分摊至该资产组的商誉账面价值，再按比例抵减其他各项资产。选A。",[("A","分摊至该资产组的商誉账面价值"),("B","各单项资产账面价值"),("C","固定资产账面价值"),("D","无形资产账面价值")]),
(175,"判断","资产组减值损失抵减后，各单项资产账面价值不得低于其单项可收回金额、公允价值减处置费用后净额和零三者中最高者。（）",["对"],"抵减后单项资产账面价值不低于三者中最高者。表述正确。"),
(176,"单选","对于难以独立产生现金流量的总部资产，进行减值测试时应当（）。",["B"],"总部资产难以独立产生现金流量，应分摊至相关资产组或资产组组合后一并测试。选B。",[("A","单独进行减值测试"),("B","分摊至相关资产组或资产组组合后进行测试"),("C","不进行减值测试"),("D","按公允价值单独测试")]),
(176,"判断","总部资产难以独立产生现金流量，应当分摊至相关资产组或资产组组合后进行减值测试。（）",["对"],"总部资产分摊后一并测试。表述正确。"),
(185,"单选","生产车间管理人员的工资，应当计入（）。",["B"],"生产工人工资计入生产成本，车间管理人员工资计入制造费用，行政人员工资计入管理费用，专设销售机构人员工资计入销售费用。选B。",[("A","生产成本"),("B","制造费用"),("C","管理费用"),("D","销售费用")]),
(185,"判断","企业应当在职工为其提供服务的会计期间，按权责发生制确认应付职工薪酬。（）",["对"],"短期薪酬按权责发生制在职工提供服务的期间确认。表述正确。"),
(186,"单选","下列带薪缺勤中，属于累积带薪缺勤、期末需要确认负债的是（）。",["A"],"累积带薪缺勤可结转下期（如年休假），需确认负债；婚假、产假、丧假属非累积带薪缺勤，不预提。选A。",[("A","年休假"),("B","婚假"),("C","产假"),("D","丧假")]),
(186,"判断","非累积带薪缺勤在实际发生缺勤的期间确认薪酬费用，不预提负债。（）",["对"],"非累积带薪缺勤实际发生时确认费用，不预提。表述正确。"),
(187,"单选","企业确认短期利润分享计划的应付职工薪酬，应当按照（）确认。",["A"],"短期利润分享计划期末按最佳估计数确认应付职工薪酬。选A。",[("A","最佳估计数"),("B","协议约定上限"),("C","实际支付数"),("D","账面利润全额")]),
(187,"判断","确认短期利润分享计划义务，须同时满足职工已提供服务且企业取得相应业绩两个条件。（）",["对"],"利润分享计划须同时满足两个条件方可确认。表述正确。"),
(192,"单选","下列各项中，属于其他长期职工福利的是（）。",["A"],"其他长期职工福利包括长期带薪缺勤、长期残疾福利、长期利润分享计划、递延奖金等；辞退福利、短期带薪缺勤、设定提存计划属其他类别。选A。",[("A","长期残疾福利"),("B","辞退福利"),("C","短期带薪缺勤"),("D","设定提存计划")]),
(192,"判断","其他长期职工福利通常按现值计量。（）",["对"],"其他长期职工福利期限超过12个月，按现值计量。表述正确。"),
]
